    input sub_A, B, Cin,
    output S, Cout
);

assign S = sub_A ^ B ^ Cin;
assign Cout = (sub_A & B) | (Cin & (sub_A ^ B));

endmodule

module four_bit_adder(
    input [3:0] sub_A, B,
    input Cin,
    output [3:0] S,
    output Cout
);

wire c1, c2, c3;
full_adder fa1(.sub_A(sub_A[0]), .B(B[0]), .Cin(Cin), .S(S[0]), .Cout(c1));
full_adder fa2(.sub_A(sub_A[1]), .B(B[1]), .Cin(c1), .S(S[1]), .Cout(c2));
full_adder fa3(.sub_A(sub_A[2]), .B(B[2]), .Cin(c2), .S(S[2]), .Cout(c3));
full_adder fa4(.sub_A(sub_A[3]), .B(B[3]), .Cin(c3), .S(S[3]), .Cout(Cout));

endmodule
